#### 任务 1: WebSocket 稳定性增强
**问题描述**: 当前 WebSocket 连接缺乏重连机制和错误处理

**改进方案**:
```typescript
// stores/websocket.ts 改进
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'

export const useWebSocketStore = defineStore('websocket', () => {
  const ws = ref<WebSocket | null>(null)
  const connected = ref(false)
  const reconnectAttempts = ref(0)
  const maxReconnectAttempts = 5
  const reconnectDelay = 3000 // 3秒

  // 心跳检测
  let heartbeatTimer: NodeJS.Timeout | null = null
  const HEARTBEAT_INTERVAL = 30000 // 30秒

  function connect() {
    if (ws.value?.readyState === WebSocket.OPEN) return

    ws.value = new WebSocket('ws://localhost:3000/api/ws')

    ws.value.onopen = () => {
      connected.value = true
      reconnectAttempts.value = 0
      startHeartbeat()
    }

    ws.value.onclose = () => {
      connected.value = false
      stopHeartbeat()
      attemptReconnect()
    }

    ws.value.onerror = (error) => {
      console.error('WebSocket error:', error)
      connected.value = false
    }

    ws.value.onmessage = (event) => {
      try {
        const { event: eventName, data } = JSON.parse(event.data)
        emit(eventName, data)
      } catch (err) {
        console.error('Failed to parse WebSocket message:', err)
      }
    }
  }

  function attemptReconnect() {
    if (reconnectAttempts.value < maxReconnectAttempts) {
      reconnectAttempts.value++
      const delay = reconnectDelay * Math.pow(2, reconnectAttempts.value - 1) // 指数退避
      setTimeout(() => {
        console.log(`Reconnecting... Attempt ${reconnectAttempts.value}`)
        connect()
      }, delay)
    } else {
      console.error('Max reconnection attempts reached')
      emit('connection.failed', { attempts: reconnectAttempts.value })
    }
  }

  function startHeartbeat() {
    heartbeatTimer = setInterval(() => {
      if (ws.value?.readyState === WebSocket.OPEN) {
        ws.value.send(JSON.stringify({ type: 'ping' }))
      }
    }, HEARTBEAT_INTERVAL)
  }

  function stopHeartbeat() {
    if (heartbeatTimer) {
      clearInterval(heartbeatTimer)
      heartbeatTimer = null
    }
  }

  function disconnect() {
    stopHeartbeat()
    ws.value?.close()
    ws.value = null
    connected.value = false
  }

  // 事件发射器
  const listeners = new Map<string, Function[]>()

  function on(event: string, callback: Function) {
    if (!listeners.has(event)) {
      listeners.set(event, [])
    }
    listeners.get(event)!.push(callback)
  }

  function emit(event: string, data: any) {
    const callbacks = listeners.get(event) || []
    callbacks.forEach(cb => cb(data))
  }

  return {
    connected,
    reconnectAttempts,
    connect,
    disconnect,
    on,
    emit
  }
})
```

