#### 任务 5: 错误边界和错误处理
**问题描述**: 缺少统一的错误处理机制

**改进方案**:
```typescript
// utils/errorHandler.ts
interface ErrorInfo {
  message: string
  code?: string
  stack?: string
  context?: Record<string, any>
}

class ErrorHandler {
  private static instance: ErrorHandler
  private errors: ErrorInfo[] = []

  static getInstance() {
    if (!ErrorHandler.instance) {
      ErrorHandler.instance = new ErrorHandler()
    }
    return ErrorHandler.instance
  }

  // 捕获 Vue 错误
  captureVueError(error: Error, instance: any, info: string) {
    this.logError({
      message: error.message,
      code: 'VUE_ERROR',
      stack: error.stack,
      context: { info, component: instance?.$options?.name }
    })
  }

  // 捕获 API 错误
  captureApiError(error: any) {
    this.logError({
      message: error.response?.data?.message || error.message,
      code: `API_ERROR_${error.response?.status}`,
      context: { url: error.config?.url, method: error.config?.method }
    })
  }

  // 捕获 WebSocket 错误
  captureWsError(error: Event) {
    this.logError({
      message: 'WebSocket connection error',
      code: 'WS_ERROR',
      context: { type: error.type }
    })
  }

  private logError(errorInfo: ErrorInfo) {
    console.error('[ErrorHandler]', errorInfo)
    this.errors.push(errorInfo)

    // 发送到错误监控服务（如 Sentry）
    this.sendToMonitoring(errorInfo)

    // 显示用户友好的错误提示
    this.showErrorNotification(errorInfo)
  }

  private sendToMonitoring(errorInfo: ErrorInfo) {
    // TODO: 集成 Sentry 或其他监控服务
  }

  private showErrorNotification(errorInfo: ErrorInfo) {
    // 使用 ElMessage 显示错误
    ElMessage.error(this.getUserFriendlyMessage(errorInfo))
  }

  private getUserFriendlyMessage(errorInfo: ErrorInfo): string {
    const messageMap: Record<string, string> = {
      'API_ERROR_401': '未授权，请重新登录',
      'API_ERROR_403': '没有权限访问',
      'API_ERROR_404': '请求的资源不存在',
      'API_ERROR_500': '服务器错误，请稍后重试',
      'WS_ERROR': '连接断开，正在尝试重新连接...',
      'VUE_ERROR': '应用程序错误，请刷新页面'
    }

    return messageMap[errorInfo.code || ''] || errorInfo.message
  }
}

export const errorHandler = ErrorHandler.getInstance()

// main.ts 中全局注册
import { errorHandler } from '@/utils/errorHandler'

app.config.errorHandler = (error, instance, info) => {
  errorHandler.captureVueError(error, instance, info)
}

// API 拦截器
axios.interceptors.response.use(
  response => response,
  error => {
    errorHandler.captureApiError(error)
    return Promise.reject(error)
  }
)
```

